4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	const THREE_RUNE_BLOCK_PREMIUM = 60;
14	
15	const basePremiumFor = (item: Item): number =>
16	  BASE_PREMIUM_BY_TYPE[item.type];
17	
18	const sumBasePremiums = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
20	
21	const isThreeRuneBlock = (items: Item[]): boolean =>
22	  items.length === 3 && items.every((item) => item.type === "rune");
23	
24	const componentsPremium = (items: Item[]): number =>
25	  isThreeRuneBlock(items) ? THREE_RUNE_BLOCK_PREMIUM : sumBasePremiums(items);
26	
27	export const quote = (input: { items: Item[] }): Quote => ({
28	  premium: componentsPremium(input.items) + PROCESSING_FEE,
29	});
30	
31	export const claim = (_input: unknown): unknown => undefined;
